#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    int highestKBitsSubarrays(vector<int>& nums, int k) {
        int result = 0;
        for (int i = 0; i < nums.size(); i++) {
            for (int j = i; j < nums.size(); j++) {
                int bits = 0;
                for (int l = 0; l < k; l++) {
                    if ((nums[j - l] >> l) & 1 == 1) {
                        bits++;
                    }
                }
                if (bits >= k) {
                    result++;
                }
            }
        }
        return result;
    }
};

int main() {
    int t;
    cin >> t;
    vector<int> nums(t);
    for (int i = 0; i < t; i++) {
        cin >> nums[i];
